class Solution:
    def minimumPushes(self, word: str) -> int:
        n = len(word)
        total = 0
        for i in range(n):
            total += i // 8 + 1
        return total

solutions.python:
class Solution:
    def minimumPushes(self, word: str) -> int:
        n = len(word)
        return sum(i // 8 + 1 for i in range(n))

